# Submit a Spark job to EMR Serverless
aws emr-serverless start-job-run \
  --application-id app-0abc123def \
  --execution-role-arn arn:aws:iam::123456789012:role/emr-serverless-role \
  --job-driver '{
    "sparkSubmit": {
      "entryPoint": "s3://my-bucket/scripts/etl.py",
      "sparkSubmitParameters": "--conf spark.executor.cores=4 --conf spark.executor.memory=8g"
    }
  }'
